import React, { useState, useEffect } from "react";
import axios from "axios";
import "./App.css";

function App() {
const [messages, setMessages] = useState([]);
const [input, setInput] = useState("");
const [loading, setLoading] = useState(false);
const [memory, setMemory] = useState({
facts: [],
topics: [],
vectors: []
});

useEffect(() => {
loadMemory();
}, []);

const loadMemory = async () => {
try {
const res = await axios.get("http://localhost:5000/api/memory");
setMemory(res.data);
} catch {}
};

const sendMessage = async () => {
if (!input.trim()) return;

```
const userMsg = { role: "user", text: input };
setMessages(prev => [...prev, userMsg]);

const currentInput = input;
setInput("");
setLoading(true);

try {
  const res = await axios.post("http://localhost:5000/api/chat", {
    message: currentInput
  });

  const aiMsg = {
    role: "ai",
    text: res.data.reply
  };

  setMessages(prev => [...prev, aiMsg]);
  loadMemory();

} catch {
  setMessages(prev => [
    ...prev,
    { role: "ai", text: "Server error" }
  ]);
}

setLoading(false);
```

};

return ( <div className="app">

```
  <div className="chat-area">
    <div className="chat-header">🤖 Memora AI</div>

    <div className="messages">
      {messages.map((msg, i) => (
        <div
          key={i}
          className={msg.role === "user" ? "user-msg" : "ai-msg"}
        >
          {msg.text}
        </div>
      ))}

      {loading && <div className="ai-msg">Thinking...</div>}
    </div>

    <div className="input-bar">
      <input
        value={input}
        onChange={(e) => setInput(e.target.value)}
        placeholder="Ask anything..."
        onKeyDown={(e) => e.key === "Enter" && sendMessage()}
      />
      <button onClick={sendMessage}>Send</button>
    </div>
  </div>

  <div className="memory-panel">
    <h3>🧠 Topics</h3>
    {memory.topics.map((t, i) => <p key={i}>{t}</p>)}

    <h3>🧍 Facts</h3>
    {memory.facts.map((f, i) => <p key={i}>{f}</p>)}
  </div>

</div>


);
}

export default App;
